/** Get a list of installs from CAPI that the current user has access to */
async getInstallList() {
	const client = new InstallApi(await this._getBaseConfig());
	return this.getAllResults<Installation>(client.listInstalls.bind(client));
}

/** List SSH keys the current user has registered with WP Engine */
async listSshKeys() {
	const client = new SshKeyApi(await this._getBaseConfig());
	return this.getAllResults<SshKey>(client.listSshKeys.bind(client));
}

/** List the Accounts a user is an Account User on (has access to) */
async getAccountList() {
	const client = new AccountApi(await this._getBaseConfig());
	return this.getAllResults<Account>(client.listAccounts.bind(client));
}

/**
 * Get a list of domains mapped to a single install
 *
 * @param installId string
 *
 * @return Promise<Domain[] | undefined>
