private async getAllResults<T>(
	apiCall: (requestParameters: { limit?: number, offset?: number}) => Promise<{ count?: number, results?: T[] }>,
): Promise<T[] | undefined> {
	const initialResponse = await apiCall({ limit: CAPIService.defaultLimit, offset: 0 });
	const { count = 0, results } = initialResponse;
	let finalResults = results || [];

	if (count > CAPIService.defaultLimit) {
		for (let offset = CAPIService.defaultLimit; offset < count; offset += CAPIService.defaultLimit) {
			const { results: paginatedResults } = await apiCall({ limit: CAPIService.defaultLimit, offset });
			if (paginatedResults) {
				finalResults = finalResults.concat(paginatedResults);
			}
		}
	}

	return finalResults;
}

/** Get a list of sites from CAPI that the current user has access to */
async getSiteList() {
	const client = new SiteApi(await this._getBaseConfig());
	return this.getAllResults<Site>(client.listSites.bind(client));
}

